		private static int EstimatedMonospacedWidth(string text)
		{
			int num = 0;
			foreach (char c in text)
			{
				if (c >= '\u3000' && c <= '〿')
				{
					num += 2;
				}
				else if (c >= '一' && c <= '鿿')
				{
					num += 2;
				}
				else
				{
					num++;
				}
			}
			return num;
		}

