		// Token: 0x06000EF6 RID: 3830 RVA: 0x00406EC4 File Offset: 0x004050C4
		public static int DamageVar(float dmg, float luck = 0f)
		{
			if (DebugOptions.NoDamageVar)
			{
				return (int)dmg;
			}
			float num = dmg * (1f + (float)Main.rand.Next(-15, 16) * 0.01f);
			if (luck > 0f)
			{
				if (Main.rand.NextFloat() < luck)
				{
					float num2 = dmg * (1f + (float)Main.rand.Next(-15, 16) * 0.01f);
					if (num2 > num)
					{
						num = num2;
					}
				}
			}
			else if (luck < 0f && Main.rand.NextFloat() < -luck)
			{
				float num3 = dmg * (1f + (float)Main.rand.Next(-15, 16) * 0.01f);
				if (num3 < num)
				{
					num = num3;
				}
			}
			return (int)Math.Round((double)num);
		}

